const items = $input.all();

function extractRawText(item) {
  let raw;

  if (Array.isArray(item.json.output)) {
    for (const outputItem of item.json.output) {
      if (outputItem.type === 'message' && Array.isArray(outputItem.content)) {
        for (const contentItem of outputItem.content) {
          if (contentItem.type === 'output_text' && typeof contentItem.text === 'string') {
            raw = contentItem.text;
            break;
          }
        }
      }
      if (raw) break;
    }
  }

  if (!raw) {
    const possibleOutputs = [
      item.json.text,
      item.json.output_text,
      item.json.response,
      item.json.message,
      item.json.content,
      item.json.data,
      item.json.result,
    ];

    raw = possibleOutputs.find(value => typeof value === 'string' && value.trim().length > 0);
  }

  return raw || '';
}

function cleanJsonText(raw) {
  return String(raw || '')
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function extractJsonObject(text) {
  const cleaned = cleanJsonText(text);
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');

  if (start === -1 || end === -1 || end <= start) {
    return cleaned;
  }

  return cleaned.slice(start, end + 1);
}

function escapeNewlinesInsideStrings(jsonText) {
  let result = '';
  let inString = false;
  let escaped = false;

  for (let i = 0; i < jsonText.length; i++) {
    const char = jsonText[i];

    if (escaped) {
      result += char;
      escaped = false;
      continue;
    }

    if (char === '\\') {
      result += char;
      escaped = true;
      continue;
    }

    if (char === '"') {
      inString = !inString;
      result += char;
      continue;
    }

    if (inString && char === '\n') {
      result += '\\n';
      continue;
    }

    if (inString && char === '\r') {
      continue;
    }

    if (inString && char === '\t') {
      result += '\\t';
      continue;
    }

    result += char;
  }

  return result;
}

function parseAiJson(raw) {
  const jsonCandidate = extractJsonObject(raw);

  try {
    return {
      parsed: JSON.parse(jsonCandidate),
      raw_output: cleanJsonText(raw),
      parse_error: '',
    };
  } catch (error) {
    const repaired = escapeNewlinesInsideStrings(jsonCandidate);

    try {
      return {
        parsed: JSON.parse(repaired),
        raw_output: cleanJsonText(raw),
        parse_error: '',
      };
    } catch (repairError) {
      return {
        parsed: null,
        raw_output: cleanJsonText(raw),
        parse_error: repairError.message,
      };
    }
  }
}

function normalizeBoolean(value) {
  if (value === true || value === 'true' || value === 'TRUE') return true;
  if (value === false || value === 'false' || value === 'FALSE') return false;
  return Boolean(value);
}

function normalizeConfidence(value) {
  const number = Number(value);

  if (Number.isNaN(number)) return 0;
  if (number < 0) return 0;
  if (number > 1) return 1;

  return number;
}

function allowedValue(value, allowed, fallback) {
  return allowed.includes(value) ? value : fallback;
}

function ensureFormattedReply(reply) {
  let text = String(reply || '').trim();

  if (!text) {
    return 'Hello,\n\nThis message needs manual review before replying.\n\nRegards,\nSupport Team';
  }

  // Convert escaped newline text into real line breaks.
  text = text
    .replace(/\\\\n/g, '\n')
    .replace(/\\n/g, '\n')
    .replace(/\r/g, '')
    .trim();

  // Clean spacing around lines.
  text = text
    .split('\n')
    .map(line => line.trim())
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  // Preserve whatever sender name the AI generated if it already has a closing.
  const hasClosing = /(Regards|Best regards|Sincerely|Thank you),?\s*\n\s*.+/i.test(text);

  if (hasClosing) {
    return text;
  }

  // Only add a generic closing if the AI forgot one.
  return `${text}\n\nRegards,\nSupport Team`;
}

return items.map((item) => {
  const raw = extractRawText(item);
  const { parsed, raw_output, parse_error } = parseAiJson(raw);

  const fallback = {
    category: 'other',
    priority: 'high',
    sentiment: 'negative',
    summary: 'AI output could not be parsed and needs manual review.',
    customer_intent: 'Unknown',
    needs_human: true,
    confidence: 0,
    suggested_reply: 'Hello,\n\nThis message needs manual review before replying.\n\nRegards,\nSupport Team',
  };

  const ai = parsed || fallback;

  const category = allowedValue(
    ai.category,
    [
      'billing',
      'refund',
      'technical_issue',
      'shipping',
      'sales',
      'complaint',
      'account',
      'follow_up',
      'other',
    ],
    'other'
  );

  const priority = allowedValue(
    ai.priority,
    ['low', 'medium', 'high', 'urgent'],
    'high'
  );

  const sentiment = allowedValue(
    ai.sentiment,
    ['positive', 'neutral', 'negative', 'angry'],
    'negative'
  );

  const confidence = normalizeConfidence(ai.confidence);
  let needsHuman = normalizeBoolean(ai.needs_human);

  if (
    confidence < 0.8 ||
    priority === 'urgent' ||
    sentiment === 'angry' ||
    category === 'refund' ||
    category === 'billing' ||
    parse_error
  ) {
    needsHuman = true;
  }

  return {
    json: {
      ...item.json,

      ticket_id:
        item.json.ticket_id ||
        `TICKET-${Date.now()}-${Math.floor(Math.random() * 10000)}`,

      ai_raw_output: raw_output,
      ai_parse_error: parse_error,

      ai_category: category,
      ai_priority: priority,
      ai_sentiment: sentiment,
      ai_summary: ai.summary || fallback.summary,
      ai_customer_intent: ai.customer_intent || fallback.customer_intent,
      ai_needs_human: needsHuman,
      ai_confidence: confidence,
      ai_suggested_reply: ensureFormattedReply(ai.suggested_reply || fallback.suggested_reply),

      conversation_type: item.json.conversation_type || 'New',
      parent_ticket_id: item.json.parent_ticket_id || '',
      previous_status: item.json.previous_status || '',
      previous_summary: item.json.previous_summary || '',
      previous_final_reply: item.json.previous_final_reply || '',
      previous_ticket_timestamp: item.json.previous_ticket_timestamp || '',
    },
  };
});

