const items = $input.all();

function truncate(text, max = 2500) {
  if (!text) return '';
  const stringText = String(text);
  return stringText.length > max
    ? stringText.slice(0, max - 20) + '... [truncated]'
    : stringText;
}

return items.map((item) => {
  const data = item.json;

  const status = data.ai_needs_human
    ? 'Pending Human Review'
    : 'Ready for Quick Review';

  const title = data.ai_needs_human
    ? '🚨 Support ticket needs review'
    : '✅ Support ticket ready for quick review';

  const payload = {
    channel: 'YOUR_SLACK_CHANNEL_ID',
    text: title,
    blocks: [
      {
        type: 'header',
        text: {
          type: 'plain_text',
          text: title,
          emoji: true,
        },
      },
      {
        type: 'section',
        fields: [
          {
            type: 'mrkdwn',
            text: `*From:*\n${data.customer_email || 'Unknown'}`,
          },
          {
            type: 'mrkdwn',
            text: `*Subject:*\n${data.subject || 'No subject'}`,
          },
          {
            type: 'mrkdwn',
            text: `*Category:*\n\`${data.ai_category || 'other'}\``,
          },
          {
            type: 'mrkdwn',
            text: `*Priority:*\n\`${data.ai_priority || 'unknown'}\``,
          },
          {
            type: 'mrkdwn',
            text: `*Sentiment:*\n\`${data.ai_sentiment || 'unknown'}\``,
          },
          {
            type: 'mrkdwn',
            text: `*Confidence:*\n\`${data.ai_confidence ?? 0}\``,
          },
        ],
      },
      {
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `*Conversation type*\n${data.conversation_type || 'New'}`
  }
},
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Summary*\n${truncate(data.ai_summary, 1000) || 'No summary available'}`,
        },
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Customer intent*\n${truncate(data.ai_customer_intent, 1000) || 'No customer intent available'}`,
        },
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Suggested reply draft*\n>${truncate(data.ai_suggested_reply, 2500) || 'No suggested reply available'}`,
        },
      },
      {
        type: 'context',
        elements: [
          {
            type: 'mrkdwn',
            text: `Click *Approve AI Reply* to send as-is, or *Needs Edit* to update \`final_reply\` in Google Sheets before sending.`,
          },
        ],
      },
      {
        type: 'context',
        elements: [
          {
            type: 'mrkdwn',
            text: `*Ticket ID:* \`${data.ticket_id}\` • *Status:* \`${status}\``,
          },
        ],
      },
      {
        type: 'actions',
        block_id: 'support_approval_actions',
        elements: [
          {
            type: 'button',
            action_id: 'approve_ai_reply',
            text: {
              type: 'plain_text',
              text: 'Approve AI Reply',
              emoji: true,
            },
            style: 'primary',
            value: `${data.ticket_id}|approve`,
          },
          {
            type: 'button',
            action_id: 'needs_edit',
            text: {
              type: 'plain_text',
              text: 'Needs Edit',
              emoji: true,
            },
            value: `${data.ticket_id}|needs_edit`,
          },
          {
            type: 'button',
            action_id: 'reject_reply',
            text: {
              type: 'plain_text',
              text: 'Reject',
              emoji: true,
            },
            style: 'danger',
            value: `${data.ticket_id}|reject`,
          },
        ],
      },
    ],
  };

  return {
    json: {
      ...data,
      status,
      slack_payload: payload
    },
  };
});

const slackResponse = $input.first().json;
const ticketData = $('Build Slack Button Payload').first().json;

return [
  {
    json: {
      ...ticketData,

      slack_ok: slackResponse.ok,
      slack_channel: slackResponse.channel,
      slack_message_ts: slackResponse.ts,
      slack_response_text: slackResponse.message?.text || '',
    }
  }
];

const currentEmail = $('Extract Email Data').first().json;
const rows = $input.all();

const sameThreadRows = rows
  .filter(item => String(item.json.gmail_thread_id || '').trim() === String(currentEmail.gmail_thread_id || '').trim())
  .filter(item => String(item.json.gmail_message_id || '').trim() !== String(currentEmail.gmail_message_id || '').trim());

// Prefer a row that was already sent, otherwise use the latest row in the thread.
const sentRows = sameThreadRows.filter(item => String(item.json.status || '').toLowerCase() === 'sent');

const candidates = sentRows.length > 0 ? sentRows : sameThreadRows;

let previousTicket = null;

if (candidates.length > 0) {
  previousTicket = candidates[candidates.length - 1].json;
}

const conversationType = previousTicket ? 'Follow-up' : 'New';

return [
  {
    json: {
      ...currentEmail,

      conversation_type: conversationType,

      parent_ticket_id: previousTicket?.ticket_id || '',
      previous_status: previousTicket?.status || '',
      previous_summary: previousTicket?.summary || previousTicket?.ai_summary || '',
      previous_final_reply: previousTicket?.final_reply || previousTicket?.suggested_reply || previousTicket?.ai_suggested_reply || '',
      previous_ticket_timestamp: previousTicket?.timestamp || previousTicket?.received_at || ''
    }
  }
];
